mapper.insert:
INSERT INTO equipment_usage (
    usage_id, equipment_asset_id, dormitory_id, room_id, employee_id,
    usage_start_date, usage_end_date, usage_quantity, remarks, created_at, updated_at
) VALUES (
    #{usageId}, #{equipmentAssetId}, #{dormitoryId}, #{roomId}, #{employeeId},
    #{usageStartDate}, #{usageEndDate}, #{usageQuantity}, #{remarks}, #{createdAt}, #{updatedAt}
)

mapper.update:
UPDATE equipment_usage
SET usage_end_date = #{usageEndDate},
    updated_at = #{updatedAt}
WHERE usage_id = #{usageId}
  AND deleted_at IS NULL
  AND usage_end_date IS NULL

mapper.select:
SELECT COALESCE(SUM(usage_quantity), 0)
FROM equipment_usage
WHERE equipment_asset_id = #{equipmentAssetId}
  AND deleted_at IS NULL
  AND usage_end_date IS NULL

    AND usage_id <> #{excludeUsageId}
